package com.example.bookservice.service;import com.example.bookservice.auth.*;import com.example.bookservice.exception.HttpStatusException;import com.example.bookservice.model.LoginRequestDto;import com.example.bookservice.model.TokenDto;import com.example.bookservice.model.UserDto;import io.grpc.StatusRuntimeException;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.InjectMocks;import org.mockito.Mock;import org.mockito.junit.jupiter.MockitoExtension;import org.springframework.http.HttpStatus;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.any;import static org.mockito.Mockito.when;@ExtendWith(MockitoExtension.class)class UserServiceTest {  @Mock private AuthServiceGrpc.AuthServiceBlockingStub authServiceBlockingStub;  @InjectMocks private UserService userService;  private LoginRequestDto loginRequestDto;  private TokenDto tokenDto;  @BeforeEach  void setUp() {    userService = new UserService(authServiceBlockingStub, "testSecretCode");    loginRequestDto = new LoginRequestDto("user1", "password123", "1234567890", "USER");    tokenDto = new TokenDto("valid-token");  }  @Test  void registerUser_Succeed() {    RegisterStatus registerStatus = RegisterStatus.newBuilder().setSuccess(true).build();    when(authServiceBlockingStub.registerUser(any(RegisterData.class))).thenReturn(registerStatus);    assertDoesNotThrow(() -> userService.registerUser(loginRequestDto));  }  @Test  void registerUser_ThrowBadRequestDataEmpty() {    LoginRequestDto invalidDto = new LoginRequestDto(null, "password123", "", null);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.registerUser(invalidDto));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Недостаточно данных.", exception.getMessage());  }  @Test  void registerUser_ThrowHttpBadGateway() {    when(authServiceBlockingStub.registerUser(any(RegisterData.class)))        .thenThrow(StatusRuntimeException.class);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.registerUser(loginRequestDto));    assertEquals(HttpStatus.BAD_GATEWAY, exception.getHttpStatus());    assertEquals("Ошибка со стороны сервера.", exception.getMessage());  }  @Test  void registerUser_ThrowBadRequestUserExist() {    RegisterStatus failStatus =        RegisterStatus.newBuilder()            .setSuccess(false)            .setMsgError("Пользователь уже существует")            .build();    when(authServiceBlockingStub.registerUser(any(RegisterData.class))).thenReturn(failStatus);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.registerUser(loginRequestDto));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Пользователь уже существует", exception.getMessage());  }  @Test  void authUser_ReturnToken() {    SessionToken sessionToken =        SessionToken.newBuilder().setSuccess(true).setToken("valid-token").build();    when(authServiceBlockingStub.authUser(any(LoginRequest.class))).thenReturn(sessionToken);    TokenDto result = userService.authUser(loginRequestDto);    assertEquals("valid-token", result.getToken());  }  @Test  void authUser_ThrowBadRequestDataEmpty() {    LoginRequestDto invalidDto = new LoginRequestDto("user1", null, null, null);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.authUser(invalidDto));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Недостаточно данных.", exception.getMessage());  }  @Test  void authUser_ThrowHttpBadGateway() {    when(authServiceBlockingStub.authUser(any(LoginRequest.class)))        .thenThrow(StatusRuntimeException.class);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.authUser(loginRequestDto));    assertEquals(HttpStatus.BAD_GATEWAY, exception.getHttpStatus());    assertEquals("Ошибка со стороны сервера.", exception.getMessage());  }  @Test  void getUser_ReturnUserData() {    UserData userData =        UserData.newBuilder()            .setLogin("user1")            .setRole(com.example.bookservice.auth.Role.USER)            .setPhone("1234567890")            .setIsActive(true)            .build();    when(authServiceBlockingStub.getUserData(any(SessionToken.class))).thenReturn(userData);    UserDto result = userService.getUser(tokenDto);    assertEquals("user1", result.getLogin());    assertEquals(Role.USER, result.getRole());    assertEquals("1234567890", result.getPhone());    assertTrue(result.isActive());  }  @Test  void getUser_ThrowBadRequestDataEmpty() {    TokenDto emptyToken = new TokenDto("");    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.getUser(emptyToken));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Недостаточно данных.", exception.getMessage());  }  @Test  void getUser_ThrowBadGateway() {    when(authServiceBlockingStub.getUserData(any(SessionToken.class)))        .thenThrow(StatusRuntimeException.class);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.getUser(tokenDto));    assertEquals(HttpStatus.BAD_GATEWAY, exception.getHttpStatus());    assertEquals("Ошибка со стороны сервера.", exception.getMessage());  }  @Test  void getUser_ThrowBadRequestTokenNotValid() {    UserData inactiveUser =        UserData.newBuilder()            .setLogin("user1")            .setRole(com.example.bookservice.auth.Role.USER)            .setPhone("1234567890")            .setIsActive(false)            .build();    when(authServiceBlockingStub.getUserData(any(SessionToken.class))).thenReturn(inactiveUser);    HttpStatusException exception =        assertThrows(HttpStatusException.class, () -> userService.getUser(tokenDto));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Невалидный токен!", exception.getMessage());  }  @Test  void giveRole_Succeed() {    UpdateStatus updateStatus = UpdateStatus.newBuilder().setSuccess(true).build();    when(authServiceBlockingStub.giveRole(any(UpdateRequest.class))).thenReturn(updateStatus);    assertDoesNotThrow(() -> userService.giveRole(loginRequestDto, "testSecretCode"));  }  @Test  void giveRole_ThrowFrobidden() {    HttpStatusException exception =        assertThrows(            HttpStatusException.class, () -> userService.giveRole(loginRequestDto, "wrongCode"));    assertEquals(HttpStatus.FORBIDDEN, exception.getHttpStatus());    assertEquals("Нет доступа.", exception.getMessage());  }  @Test  void giveRole_ThrowBadRequestDataEmpty() {    LoginRequestDto invalidDto = new LoginRequestDto(null, null, null, null);    HttpStatusException exception =        assertThrows(            HttpStatusException.class, () -> userService.giveRole(invalidDto, "testSecretCode"));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Недостаточно данных.", exception.getMessage());  }  @Test  void giveRole_ThrowBadGateway() {    when(authServiceBlockingStub.giveRole(any(UpdateRequest.class)))        .thenThrow(StatusRuntimeException.class);    HttpStatusException exception =        assertThrows(            HttpStatusException.class,            () -> userService.giveRole(loginRequestDto, "testSecretCode"));    assertEquals(HttpStatus.BAD_GATEWAY, exception.getHttpStatus());    assertEquals("Ошибка со стороны сервера.", exception.getMessage());  }  @Test  void giveRole_ThrowBadRequestUserNotFound() {    UpdateStatus failStatus =        UpdateStatus.newBuilder().setSuccess(false).setMsgError("Пользователь не найден").build();    when(authServiceBlockingStub.giveRole(any(UpdateRequest.class))).thenReturn(failStatus);    HttpStatusException exception =        assertThrows(            HttpStatusException.class,            () -> userService.giveRole(loginRequestDto, "testSecretCode"));    assertEquals(HttpStatus.BAD_REQUEST, exception.getHttpStatus());    assertEquals("Пользователь не найден", exception.getMessage());  }}